// Cookie-String aus dem ersten Node holen
const cookieItem = $('Cookies aus NocoDB').first();
const cookie = cookieItem.json.Cookie || '';

// Jeden Event mit Cookie anreichern
return $input.all().map(item => ({
  json: { ...item.json, _cookie: cookie }
}));

const html = $input.item.json.data || $input.item.json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

const toInt = str => str ? parseInt(str.replace(/[^\d]/g, ''), 10) : 0;

const angemeldetMatch  = htmlStr.match(/(\d+)\s*Personen angemeldet/)  || htmlStr.match(/>(\d+)<[^>]*>\s*Personen angemeldet/);
const nichtBestMatch   = htmlStr.match(/(\d+)\s*noch nicht bestätigt/) || htmlStr.match(/(\d+)\s*nicht bestätigt/);
const vorgemerktMatch  = htmlStr.match(/(\d+)\s*mal vorgemerkt/);
const aufrufMatch      = htmlStr.match(/(\d+)\s*Aufrufe/);
const maennerMatch     = htmlStr.match(/Männer[^(]*\((\d+)\)/)         || htmlStr.match(/M.nner[^(]*\((\d+)\)/);
const frauenMatch      = htmlStr.match(/Frauen[^(]*\((\d+)\)/);
const paareMatch       = htmlStr.match(/Paare[^(]*\((\d+)\)/);

// Event-Coverbild aus og:image Meta-Tag extrahieren
let eventBildUrl = '';
const ogM = htmlStr.match(/property="og:image"\s+content="([^"]+)"/i)
         || htmlStr.match(/content="([^"]+)"\s+property="og:image"/i);
if (ogM && ogM[1] && ogM[1].startsWith('http')) eventBildUrl = ogM[1];

// Event-ID und vorhandenes Bild aus vorherigem Item
const prevJson = $('Cookie anhängen').item.json;
let existingBild = '';
try {
  const att = prevJson['Event-Bild'];
  if (att) {
    const p = typeof att === 'string' ? JSON.parse(att) : att;
    if (Array.isArray(p) && p.length > 0) existingBild = p[0].signedPath || p[0].path || p[0].url || '';
  }
} catch(e) {}

return [{ json: {
  _id:             prevJson.Id,
  Angemeldet:      angemeldetMatch  ? toInt(angemeldetMatch[1])  : 0,
  NichtBestaetigt: nichtBestMatch   ? toInt(nichtBestMatch[1])   : 0,
  Vorgemerkt:      vorgemerktMatch  ? toInt(vorgemerktMatch[1])  : 0,
  Aufrufe:         aufrufMatch      ? toInt(aufrufMatch[1])      : 0,
  Maenner:         maennerMatch     ? toInt(maennerMatch[1])     : 0,
  Frauen:          frauenMatch      ? toInt(frauenMatch[1])      : 0,
  Paare:           paareMatch       ? toInt(paareMatch[1])       : 0,
  _eventBildUrl:   eventBildUrl,
  _existingBild:   existingBild
}}];

